############################################# ### Generated from PreTeXt source ### ### https://pretextbook.org ### ############################################# ## DBsubject() ## DBchapter() ## DBsection() ## Level() ## KEYWORDS() ## TitleText1() ## EditionText1() ## AuthorText1() ## Section1(not reported) ## Problem1(1.2.9.116) ## Author() ## Institution() ## Language(en-US)
DOCUMENT();
############################################################ # Load Macros ############################################################ loadMacros( "PGstandard.pl", "PGML.pl", "AnswerFormatHelp.pl", "parserNumberWithUnits.pl", "randomPerson.pl", "PGcourse.pl", ); COMMENT('Authored in PreTeXt');
############################################################ # Header ############################################################ TEXT(beginproblem());
############################################################ # PG Setup Code ############################################################ Context('Numeric'); $name = randomPerson(); $initial = random(12, 18); $start = NumberWithUnits("$initial gal"); $rate = random(0.04,0.05,0.001); $speed = NumberWithUnits("$rate gal"); $final = 1; $end = NumberWithUnits("$final gal"); $solution = ($initial - $final)/$rate; $distance = NumberWithUnits("$solution mi");
############################################################ # Body ############################################################
BEGIN_PGML [$name] filled the gas tank in [$name->possessive] car to [`[$start]\text{.}`] When the tank reaches [`[$end]\text{,}`] the low gas light will come on. On average, [$name]'s car uses [`[$speed]`] per mile driven. How many miles will [$name]'s car be able to drive before the low gas light comes on?
[_]{$distance}{20}
END_PGML
############################################################ # End Problem ############################################################
ENDDOCUMENT();
